"""Реестр сигналов, шумов и фильтров."""from __future__ import annotationsfrom typing import Iterablefrom .interfaces import IFilter, INoise, ISignalclass RegistryError(KeyError):    """Коллизия или запрос несуществующего компонента."""class Registry:    def __init__(self) -> None:        self._signals: dict[str, ISignal] = {}        self._noises: dict[str, INoise] = {}        self._filters: dict[str, IFilter] = {}    def register_signal(self, impl: ISignal) -> None:        self._check_name("signal", impl)        if impl.name in self._signals:            raise RegistryError(f"signal name already registered: {impl.name!r}")        self._signals[impl.name] = impl    def register_noise(self, impl: INoise) -> None:        self._check_name("noise", impl)        if impl.name in self._noises:            raise RegistryError(f"noise name already registered: {impl.name!r}")        self._noises[impl.name] = impl    def register_filter(self, impl: IFilter) -> None:        self._check_name("filter", impl)        if impl.name in self._filters:            raise RegistryError(f"filter name already registered: {impl.name!r}")        self._filters[impl.name] = impl    def get_signal(self, name: str) -> ISignal:        try:            return self._signals[name]        except KeyError:            raise RegistryError(                f"signal not found: {name!r}. Available: {self.list_signals()}"            ) from None    def get_noise(self, name: str) -> INoise:        try:            return self._noises[name]        except KeyError:            raise RegistryError(                f"noise not found: {name!r}. Available: {self.list_noises()}"            ) from None    def get_filter(self, name: str) -> IFilter:        try:            return self._filters[name]        except KeyError:            raise RegistryError(                f"filter not found: {name!r}. Available: {self.list_filters()}"            ) from None    def list_signals(self) -> list[str]:        return list(self._signals.keys())    def list_noises(self) -> list[str]:        return list(self._noises.keys())    def list_filters(self) -> list[str]:        return list(self._filters.keys())    def __repr__(self) -> str:        return (f"Registry(signals={len(self._signals)}, "                f"noises={len(self._noises)}, filters={len(self._filters)})")    @staticmethod    def _check_name(kind: str, impl: object) -> None:        name = getattr(impl, "name", None)        if not isinstance(name, str) or not name.strip():            raise RegistryError(f"{kind}: attribute 'name' must be a non-empty string")def create_default_registry() -> Registry:    from ..filters import BUILTIN_FILTERS    from ..noises import BUILTIN_NOISES    from ..signals import BUILTIN_SIGNALS    return register_builtins(        Registry(),        signals=BUILTIN_SIGNALS,        noises=BUILTIN_NOISES,        filters=BUILTIN_FILTERS,    )def register_builtins(registry: Registry, *,                      signals: Iterable[ISignal] = (),                      noises: Iterable[INoise] = (),                      filters: Iterable[IFilter] = ()) -> Registry:    for s in signals:        registry.register_signal(s)    for n in noises:        registry.register_noise(n)    for f in filters:        registry.register_filter(f)    return registry